88	      full_o     => full_o,
89	      empty_o    => empty_o,
90	      alm_full_o  => alm_full_o,
91	      alm_empty_o => alm_empty_o,
92	      in_level_o  => in_level_o,
93	      out_level_o => out_level_o
94	    );
