111	  -------------------------------------------------------------------------
112	  -- TB Control
113	  -------------------------------------------------------------------------
114	  p_control : process
115	  begin
116	    -- *** Reset Tests ***
117	    print(">> Reset");
118	    -- Reset
119	    rst_i <= '1';
120	    wait until rising_edge(clk_i);
121	    -- check if ready state during reset is correct
122	    assert rdy_o = int_to_std_logic(rdy_rst_state_g) report "###ERROR###: rdy_o reset state not according to generic" severity error;
123	    wait for 1 us;
124	
125	    -- Remove reset
126	    wait until rising_edge(clk_i);
127	    rst_i <= '0';
128	
129	    -- Check Reset State
130	    wait until rising_edge(clk_i);
131	    assert rdy_o = '1' report "###ERROR###: rdy_o after reset state not '1'" severity error;
132	    assert vld_o = '0' report "###ERROR###: vld_o reset state not '0'" severity error;
133	    assert full_o = '0' report "###ERROR###: full_o reset state not '0'" severity error;
134	    assert empty_o = '1' report "###ERROR###: empty_o reset state not '1'" severity error;
135	    assert unsigned(in_level_o) = 0 report "###ERROR###: in_level_o reset state not 0" severity error;
136	    assert unsigned(out_level_o) = 0 report "###ERROR###: in_level_o reset state not 0" severity error;
137	    if alm_full_on_g then
138	      assert alm_full_o = '0' report "###ERROR###: alm_full_o reset state not '0'" severity error;
139	    end if;
140	    if alm_empty_on_g then
141	      assert alm_empty_o = '1' report "###ERROR###: alm_empty_o reset state not '1'" severity error;
142	    end if;
143	
144	    -- *** Two words write then read ***
145	    print(">> Two words write then read");
146	    -- Write 1
147	    wait until falling_edge(clk_i);
148	    dat_i <= X"0001";
149	    vld_i  <= '1';
150	    assert rdy_o = '1' report "###ERROR###: rdy_o went low unexpectedly" severity error;
151	    assert vld_o = '0' report "###ERROR###: vld_o wnt high unexpectedly" severity error;
152	    assert empty_o = '1' report "###ERROR###: empty_o not high" severity error;
153	    assert unsigned(in_level_o) = 0 report "###ERROR###: in_level_o not 0" severity error;
154	    assert unsigned(out_level_o) = 0 report "###ERROR###: out_level_o not 0" severity error;
155	    -- Write 2
156	    wait until falling_edge(clk_i);
157	    dat_i <= X"0002";
158	    assert rdy_o = '1' report "###ERROR###: rdy_o went low unexpectedly" severity error;
159	    assert vld_o = '0' report "###ERROR###: vld_o wnt high unexpectedly" severity error;
160	    assert empty_o = '1' report "###ERROR###: empty_o not high" severity error;
161	    assert unsigned(in_level_o) = 1 report "###ERROR###: in_level_o not 1" severity error;
162	    assert unsigned(out_level_o) = 0 report "###ERROR###: out_level_o not 0" severity error;
163	    -- Pause 1
164	    wait until falling_edge(clk_i);
165	    dat_i <= X"0003";
166	    vld_i  <= '0';
167	    assert rdy_o = '1' report "###ERROR###: rdy_o went low unexpectedly" severity error;
168	    assert vld_o = '1' report "###ERROR###: vld_o not high" severity error;
169	    assert dat_o = X"0001" report "###ERROR###: Illegal dat_o 1" severity error;
170	    assert empty_o = '0' report "###ERROR###: empty_o not low" severity error;
171	    assert unsigned(in_level_o) = 2 report "###ERROR###: in_level_o not 2" severity error;
172	    assert unsigned(out_level_o) = 1 report "###ERROR###: out_level_o not 1" severity error;
173	    -- Pause 2
