180	    assert unsigned(out_level_o) = 2 report "###ERROR###: out_level_o not 2" severity error;
181	    -- Read ack 1
182	    wait until falling_edge(clk_i);
183	    rdy_i <= '1';
184	    assert rdy_o = '1' report "###ERROR###: rdy_o went low unexpectedly" severity error;
185	    assert vld_o = '1' report "###ERROR###: vld_o not high" severity error;
186	    assert dat_o = X"0001" report "###ERROR###: Illegal dat_o 1" severity error;
187	    assert empty_o = '0' report "###ERROR###: empty_o not low" severity error;
188	    assert unsigned(in_level_o) = 2 report "###ERROR###: in_level_o not 2" severity error;
189	    assert unsigned(out_level_o) = 2 report "###ERROR###: out_level_o not 2" severity error;
190	    -- Read ack 2
191	    wait until falling_edge(clk_i);
192	    assert rdy_o = '1' report "###ERROR###: rdy_o went low unexpectedly" severity error;
193	    assert vld_o = '1' report "###ERROR###: vld_o not high" severity error;
194	    assert dat_o = X"0002" report "###ERROR###: Illegal dat_o 2" severity error;
195	    assert empty_o = '0' report "###ERROR###: empty_o not low" severity error;
196	    assert unsigned(in_level_o) = 2 report "###ERROR###: in_level_o not 2" severity error;
197	    assert unsigned(out_level_o) = 1 report "###ERROR###: out_level_o not 2" severity error;
198	    -- empty 1
199	    wait until falling_edge(clk_i);
200	    rdy_i <= '0';
201	    assert rdy_o = '1' report "###ERROR###: rdy_o went low unexpectedly" severity error;
202	    assert vld_o = '0' report "###ERROR###: vld_o not high" severity error;
203	    assert empty_o = '1' report "###ERROR###: empty_o not high" severity error;
204	    assert unsigned(in_level_o) = 1 report "###ERROR###: in_level_o not 2" severity error;
205	    assert unsigned(out_level_o) = 0 report "###ERROR###: out_level_o not 2" severity error;
206	    -- empty 2
207	    wait until falling_edge(clk_i);
208	    assert rdy_o = '1' report "###ERROR###: rdy_o went low unexpectedly" severity error;
209	    assert vld_o = '0' report "###ERROR###: vld_o not high" severity error;
210	    assert empty_o = '1' report "###ERROR###: empty_o not high" severity error;
211	    assert unsigned(in_level_o) = 0 report "###ERROR###: in_level_o not 2" severity error;
212	    assert unsigned(out_level_o) = 0 report "###ERROR###: out_level_o not 2" severity error;
213	
214	    -- *** Write into Full FIFO ***
215	    wait until falling_edge(clk_i);
216	    print(">> Write into full_o FIFO");
217	    -- Fill FIFO
218	    for i in 0 to depth_g - 1 loop
219	      vld_i  <= '1';
220	      dat_i <= std_logic_vector(to_unsigned(i, dat_i'length));
221	      wait until falling_edge(clk_i);
222	    end loop;
223	    vld_i  <= '0';
224	    wait until falling_edge(clk_i);
225	    wait until falling_edge(clk_i);
226	    assert full_o = '1' report "###ERROR###: Fully not asserted" severity error;
227	    assert unsigned(in_level_o) = depth_g report "###ERROR###: in_level_o not full_o" severity error;
228	    assert unsigned(out_level_o) = depth_g report "###ERROR###: out_level_o not full_o" severity error;
229	    -- Add more data (not written because full)
230	    vld_i  <= '1';
231	    dat_i <= X"ABCD";
232	    wait until falling_edge(clk_i);
233	    dat_i <= X"8765";
234	    wait until falling_edge(clk_i);
235	    vld_i  <= '0';
236	    wait until falling_edge(clk_i);
237	    wait until falling_edge(clk_i);
238	    assert full_o = '1' report "###ERROR###: Fully not asserted" severity error;
239	    assert unsigned(in_level_o) = depth_g report "###ERROR###: in_level_o not full_o" severity error;
240	    assert unsigned(out_level_o) = depth_g report "###ERROR###: out_level_o not full_o" severity error;
241	    -- Check read
242	    for i in 0 to depth_g - 1 loop
243	      rdy_i <= '1';
244	      assert unsigned(dat_o) = i report "###ERROR: Read wrong data in word " & integer'image(i) severity error;
245	      wait until falling_edge(clk_i);
246	    end loop;
247	    rdy_i <= '0';
248	    wait until falling_edge(clk_i);
249	    wait until falling_edge(clk_i);
250	    assert empty_o = '1' report "###ERROR###: empty_o not asserted" severity error;
251	    assert full_o = '0' report "###ERROR###: Fully not de-asserted" severity error;
252	    assert unsigned(in_level_o) = 0 report "###ERROR###: in_level_o not empty_o" severity error;
253	    assert unsigned(out_level_o) = 0 report "###ERROR###: out_level_o not empty_o" severity error;
254	
255	    -- *** Read from Empty Fifo ***
256	    wait until falling_edge(clk_i);
257	    print(">> Read from empty_o FIFO");
258	    assert empty_o = '1' report "###ERROR###: empty_o not asserted" severity error;
259	    -- read
260	    wait until falling_edge(clk_i);
261	    rdy_i <= '1';
262	    wait until falling_edge(clk_i);
263	    rdy_i <= '0';
264	    -- check correct functionality
265	    wait until falling_edge(clk_i);
266	    wait until falling_edge(clk_i);
267	    assert empty_o = '1' report "###ERROR###: empty_o not asserted" severity error;
268	    assert unsigned(in_level_o) = 0 report "###ERROR###: in_level_o not empty_o" severity error;
269	    assert unsigned(out_level_o) = 0 report "###ERROR###: out_level_o not empty_o" severity error;
270	    vld_i  <= '1';
271	    dat_i <= X"8765";
272	    wait until falling_edge(clk_i);
273	    vld_i  <= '0';
274	    wait until falling_edge(clk_i);
275	    wait until falling_edge(clk_i);
276	    assert empty_o = '0' report "###ERROR###: empty_o not de-asserted" severity error;
277	    assert unsigned(in_level_o) = 1 report "###ERROR###: in_level_o not empty_o" severity error;
278	    assert unsigned(out_level_o) = 1 report "###ERROR###: out_level_o not empty_o" severity error;
279	    assert dat_o = X"8765" report "###ERROR: Read wrong data" severity error;
280	    rdy_i <= '1';
281	    wait until falling_edge(clk_i);
282	    rdy_i <= '0';
283	    wait until falling_edge(clk_i);
284	    wait until falling_edge(clk_i);
285	    assert empty_o = '1' report "###ERROR###: empty_o not asserted" severity error;
286	    assert unsigned(in_level_o) = 0 report "###ERROR###: in_level_o not empty_o" severity error;
287	    assert unsigned(out_level_o) = 0 report "###ERROR###: out_level_o not empty_o" severity error;
288	
289	    -- *** Almost full/almost empty
290	    print(">> Almost full_o/almost empty_o");
291	    -- fill
292	    for i in 0 to depth_g - 1 loop
293	      vld_i  <= '1';
294	      dat_i <= std_logic_vector(to_unsigned(i, dat_i'length));
295	      wait until falling_edge(clk_i);
296	      vld_i  <= '0';
297	      wait until falling_edge(clk_i);
298	      wait until falling_edge(clk_i);
299	      assert unsigned(in_level_o) = i + 1 report "###ERROR###: in_level_o wrong" severity error;
300	      assert unsigned(out_level_o) = i + 1 report "###ERROR###: out_level_o wrong" severity error;
301	      if alm_full_on_g then
302	        if i + 1 >= AlmFullLevel_c then
303	          assert alm_full_o = '1' report "###ERROR###: Almost full_o not set" severity error;
304	        else
305	          assert alm_full_o = '0' report "###ERROR###: Almost full_o set" severity error;
306	        end if;
307	      end if;
308	      if alm_empty_on_g then
309	        if i + 1 <= AlmEmptyLevel_c then
310	          assert alm_empty_o = '1' report "###ERROR###: Almost empty_o not set" severity error;
311	        else
312	          assert alm_empty_o = '0' report "###ERROR###: Almost empty_o set" severity error;
313	        end if;
314	      end if;
315	    end loop;
316	    -- flush
317	    for i in depth_g - 1 downto 0 loop
318	      rdy_i <= '1';
319	      wait until falling_edge(clk_i);
320	      rdy_i <= '0';
321	      wait until falling_edge(clk_i);
322	      wait until falling_edge(clk_i);
323	      assert unsigned(in_level_o) = i report "###ERROR###: in_level_o wrong" severity error;
324	      assert unsigned(out_level_o) = i report "###ERROR###: out_level_o wrong" severity error;
325	      if alm_full_on_g then
326	        if i >= AlmFullLevel_c then
327	          assert alm_full_o = '1' report "###ERROR###: Almost full_o not set" severity error;
328	        else
329	          assert alm_full_o = '0' report "###ERROR###: Almost full_o set" severity error;
330	        end if;
331	      end if;
332	      if alm_empty_on_g then
333	        if i <= AlmEmptyLevel_c then
334	          assert alm_empty_o = '1' report "###ERROR###: Almost empty_o not set" severity error;
335	        else
336	          assert alm_empty_o = '0' report "###ERROR###: Almost empty_o set" severity error;
337	        end if;
338	      end if;
339	    end loop;
340	
341	    -- Different duty cycles
342	    print(">> Different Duty Cycles");
343	    wait until falling_edge(clk_i);
344	    for wrDel in 0 to 4 loop
345	      for rdDel in 0 to 4 loop
346	        assert empty_o = '1' report "###ERROR###: empty_o not asserted" severity error;
347	        -- Write data
348	        for i in 0 to 4 loop
349	          vld_i  <= '1';
350	          dat_i <= std_logic_vector(to_unsigned(i, dat_i'length));
351	          wait until falling_edge(clk_i);
352	          for k in 1 to wrDel loop
353	            vld_i  <= '0';
354	            dat_i <= X"0000";
355	            wait until falling_edge(clk_i);
356	          end loop;
357	        end loop;
358	        vld_i  <= '0';
359	        -- Read data
360	        for i in 0 to 4 loop
361	          rdy_i <= '1';
362	          assert unsigned(dat_o) = i report "###ERROR###: Wrong data" severity error;
363	          wait until falling_edge(clk_i);
364	          for k in 1 to rdDel loop
365	            rdy_i <= '0';
366	            wait until falling_edge(clk_i);
367	          end loop;
368	        end loop;
369	        rdy_i <= '0';
370	        assert empty_o = '1' report "###ERROR###: empty_o not asserted" severity error;
371	      end loop;
372	    end loop;
373	
374	    -- TB done
375	    TbRunning <= false;
376	    wait;
377	  end process;
378	
